import dataclasses, datetime
from typing import Optional

@dataclasses.dataclass
class KpiSnapshot:
    kpi_id: str
    kpi_name: str
    tier: int                      # 1–4
    value: float
    unit: str                      # e.g. "$", "%", "h"
    period: str                    # e.g. "2025-06" or "2025-Q2"
    target: Optional[float]
    target_direction: str          # "lower" | "higher" | "within_range"
    target_min: Optional[float] = None  # for "within_range"
    target_max: Optional[float] = None
    definition_version: str = "v1"
    notes: str = ""

    @property
    def meets_target(self) -> bool:
        if self.target is None:
            return True
        if self.target_direction == "lower":
            return self.value <= self.target
        if self.target_direction == "higher":
            return self.value >= self.target
        if self.target_direction == "within_range":
            lo = self.target_min or 0.0
            hi = self.target_max or float("inf")
            return lo <= self.value <= hi
        return False

    @property
    def status(self) -> str:
        if not self.meets_target:
            return "off-target"
        return "on-target"

    def format_summary(self) -> str:
        target_str = f"{self.target}" if self.target else "—"
        return (
            f"{self.kpi_name} ({self.period}): {self.value:.3f}{self.unit}  "
            f"Target: {target_str}  [{self.status}]"
        )


@dataclasses.dataclass
class KpiLedger:
    snapshots: list = dataclasses.field(default_factory=list)

    def add(self, snapshot: KpiSnapshot) -> None:
        self.snapshots.append(snapshot)

    def history(self, kpi_id: str) -> list[KpiSnapshot]:
        return sorted(
            [s for s in self.snapshots if s.kpi_id == kpi_id],
            key=lambda s: s.period
        )

    def latest(self, kpi_id: str) -> Optional[KpiSnapshot]:
        h = self.history(kpi_id)
        return h[-1] if h else None

    def off_target_kpis(self) -> list[KpiSnapshot]:
        """Return the most recent snapshot for each KPI that is off-target."""
        seen = {}
        for s in sorted(self.snapshots, key=lambda x: x.period, reverse=True):
            if s.kpi_id not in seen:
                seen[s.kpi_id] = s
        return [s for s in seen.values() if not s.meets_target]

@dataclasses.dataclass
class ImprovementTarget:
    kpi_id: str
    kpi_name: str
    baseline_value: float
    baseline_period: str
    target_value: float
    target_period: str
    improvement_lever: str
    owner: str

    @property
    def required_change_pct(self) -> float:
        if self.baseline_value == 0:
            return 0.0
        return (self.target_value - self.baseline_value) / self.baseline_value

    def progress(self, current_value: float) -> float:
        """Returns 0.0 (no progress) to 1.0 (target met)."""
        total_change_needed = self.target_value - self.baseline_value
        if total_change_needed == 0:
            return 1.0
        actual_change = current_value - self.baseline_value
        return max(0.0, min(1.0, actual_change / total_change_needed))

    def format_progress_report(self, current_value: float) -> str:
        pct = self.progress(current_value)
        bar = "█" * int(pct * 10) + "░" * (10 - int(pct * 10))
        return (
            f"{self.kpi_name}: [{bar}] {pct:.0%}\n"
            f"  Baseline: {self.baseline_value:.3f}  Current: {current_value:.3f}  "
            f"Target: {self.target_value:.3f}  Lever: {self.improvement_lever}"
        )

def linear_trend(values: list[float]) -> tuple[float, float]:
    """Return (slope, intercept) for OLS fit on index-indexed values."""
    n = len(values)
    if n < 2:
        return 0.0, values[0] if values else 0.0
    x_mean = (n - 1) / 2
    y_mean = sum(values) / n
    numerator = sum((i - x_mean) * (v - y_mean) for i, v in enumerate(values))
    denominator = sum((i - x_mean) ** 2 for i in range(n))
    slope = numerator / denominator if denominator else 0.0
    intercept = y_mean - slope * x_mean
    return slope, intercept


def project_end_of_quarter(
    weekly_values: list[float],
    weeks_remaining: int,
) -> float:
    """Project KPI value at end-of-quarter given recent weekly observations."""
    slope, intercept = linear_trend(weekly_values)
    future_index = len(weekly_values) - 1 + weeks_remaining
    return intercept + slope * future_index


def detect_regression(
    weekly_values: list[float],
    target: float,
    target_direction: str,
    regression_threshold: float = 0.05,
) -> bool:
    """Return True if the current trend is moving away from target."""
    if len(weekly_values) < 4:
        return False
    slope, _ = linear_trend(weekly_values[-4:])
    if target_direction == "lower":
        return slope > regression_threshold * abs(weekly_values[-1])
    if target_direction == "higher":
        return slope < -regression_threshold * abs(weekly_values[-1])
    return False
